1: // ── Boot Sequence: ties every module together ──
2: // Execution order:
3: //   1. DOMContentLoaded
4: //   2. Open laptop lid (CSS animation)
5: //   3. Display boot lines one-by-one in #boot-overlay
6: //   4. Remove overlay; mount jQuery Terminal
7: //   5. Print FIGlet banner + welcome message
8: //   6. Start ambient audio
9: //   7. Hand off to interactive Commands.interpreter
10: 
11: (function () {
12: 
13:   const BOOT_LINES = [
14:     { text: 'BIOS v2.1 — Detecting hardware...',        cls: 'dim'  },
15:     { text: '[  OK  ] CPU: x86_64 cortex-A72 @ 2.4GHz', cls: 'ok'  },
16:     { text: '[  OK  ] RAM: 16 GB DDR4',                  cls: 'ok'  },
17:     { text: '[  OK  ] Display: Amber CRT 680×440',       cls: 'ok'  },
18:     { text: '[  OK  ] Keyboard: Model M (vintage)',       cls: 'ok'  },
19:     { text: '',                                           cls: ''    },
20:     { text: 'Loading CLI-OS kernel v4.2...',             cls: 'info' },
21:     { text: '[  OK  ] Mounting /home/{{owner}}',         cls: 'ok'  },
22:     { text: '[  OK  ] Importing skill-set modules...',   cls: 'ok'  },
23:     { text: '[  OK  ] Starting virtual host: {{host}}',  cls: 'ok'  },
24:     { text: '[  OK  ] Activating CRT scanline driver',   cls: 'ok'  },
25:     { text: '[  OK  ] Injecting personality matrix...',  cls: 'ok'  },
26:     { text: '[  OK  ] Spawning AI assistant (Ezra)',     cls: 'ok'  },
27:     { text: '',                                           cls: ''    },
28:     { text: '[[  OK  ]] System ready.',                  cls: 'ok'  },
29:   ];
30: 
31:   // Interpolate {{tokens}} using CFG
32:   function interpolate (str) {
33:     return str
34:       .replace('{{owner}}', CFG.owner)
35:       .replace('{{host}}',  CFG.host);
36:   }
37: 
38:   // Type-write a single line into the overlay
39:   function printLine (overlay, line) {
40:     return new Promise(resolve => {
41:       const span = document.createElement('span');
42:       span.className = line.cls || '';
43:       overlay.appendChild(span);
44:       overlay.appendChild(document.createTextNode('\n'));
45: 
46:       const text = interpolate(line.text);
47:       let   i    = 0;
48: 
49:       const t = setInterval(() => {
50:         span.textContent += text[i++] || '';
51:         if (i >= text.length) { clearInterval(t); resolve(); }
52:       }, 12);
53:     });
54:   }
55: 
56:   async function runBoot () {
57:     // Wait for data to load (PF window global set by data.js)
58:     await new Promise(res => {
59:       const check = () => window.PF ? res() : setTimeout(check, 50);
60:       check();
61:     });
62: 
63:     Commands.init();   // populate FS with project slugs
64: 
65:     // ── Step 1: Open Lid ──────────────────────────────
66: 
67:     const overlay = document.getElementById('boot-overlay');
68:     overlay.classList.add('active');
69:     Laptop.openLid();
70: 
71:     // ── Step 2: Boot Lines ────────────────────────────
72: 
73:     await new Promise(res => setTimeout(res, 400));   // small pre-boot pause
74: 
75:     for (const line of BOOT_LINES) {
76:       await printLine(overlay, line);
77:       await new Promise(res => setTimeout(res, CFG.bootLineDelay));
78:     }
79: 
80:     await new Promise(res => setTimeout(res, 600));
81: 
82:     // ── Step 3: Hide overlay; mount terminal ──────────
83: 
84:     overlay.classList.remove('active');
85: 
86:     // ── Step 4: Mount jQuery Terminal ─────────────────
87: 
88:     const term = $('#terminal-mount').terminal(Commands.interpreter, {
89:       greetings:     false,   // we print our own
90:       name:          'portfolio',
91:       prompt:        `[[b;#ff8c00;]${CFG.handle}@${CFG.host}]:[[;#ffd060;]~]$ `,
92:       autocomplete:  CFG.commands,
93:       tabcompletion: true,
94:       exit:          false,
95:       checkArity:    false,
96:       historySize:   80,
97:     });
98: 
99:     // Expose for easter-egg use
100:     window.__term__ = term;
101: 
102:     // ── Step 5: FIGlet Banner ─────────────────────────
103: 
104:     await new Promise(res => {
105:       figlet.text(CFG.owner.split(' ')[0], { font: 'Standard' }, (err, banner) => {
106:         if (!err && banner) {
107:           const lines = banner.split('\n');
108:           lines.forEach(l => term.echo(`[[;#ff6600;]${l}]`));
109:         }
110:         res();
111:       });
112:     });
113: 
114:     // Welcome message
115:     term.echo('');
116:     term.echo(`[[b;#ffb000;]Welcome to ${CFG.owner}'s CLI Portfolio]`);
117:     term.echo(`[[;#888;]Type [[b;#ffd060;]help] to see available commands.]`);
118: 
119:     // Seasonal greeting
120:     const greeting = window.Easter.timeGreeting();
121:     if (greeting) term.echo(`[[;#00e676;]${greeting}]`);
122: 
123:     term.echo('');
124: 
125:     // ── Step 6: Ambient Audio ─────────────────────────
126:     Audio_.play();
127:   }
128: 
129:   // Kick off on DOM ready
130:   document.addEventListener('DOMContentLoaded', runBoot);
131: 
132: })();
