3: (function () {
4:   let audio = null;
5:   let muted = false;
6: 
7:   function init () {
8:     if (!CFG.audioSrc) return;
9:     audio        = new Audio(CFG.audioSrc);
10:     audio.loop   = true;
11:     audio.volume = CFG.audioVol;
12: 
13:     document.getElementById('btn-mute')
14:       .addEventListener('click', toggle);
15:   }
16: 
17:   function play () {
18:     if (!audio) init();
19:     if (!audio) return;
20:     if (!muted) audio.play().catch(() => {
21:       // Autoplay blocked: wait for first user interaction
22:       document.addEventListener('keydown', () => audio.play(), { once: true });
23:     });
24:   }
25: 
26:   function toggle () {
27:     muted = !muted;
28:     if (audio) {
29:       muted ? audio.pause() : audio.play();
30:     }
31:     document.getElementById('mute-icon').textContent = muted ? '🔇' : '🔊';
32:   }
33: 
34:   // Expose globally
35:   window.Audio_ = { play, toggle };
36: })();
