 * ─────────────────────────────────────────────────────
 */

import portfolioData from '../data/portfolio.json';
import { config } from './config';
import { themes } from './themes';
import type { Terminal } from '@xterm/xterm';

/* ── Portfolio data accessors ────────────────────────── */
const data = portfolioData as {
  owner: { name: string; handle: string; host: string; title: string; tagline: string; location: string; email: string; github: string; linkedin: string };
  about: string[];
  skills: Record<string, string[]>;
  projects: { slug: string; name: string; desc: string; tech: string[]; url: string; year: number }[];
  contact: { email: string; github: string; linkedin: string; twitter: string };
};

/**
 * Writer interface — abstracts xterm writes so commands
 * don't need direct terminal access.
 */
export interface TerminalWriter {
  /** Write a line with optional ANSI codes */
  writeln: (text: string) => void;
  /** Write inline (no newline) */
  write: (text: string) => void;
  /** Clear the screen */
  clear: () => void;
  /** Access the raw xterm Terminal for theme changes etc. */
  terminal: Terminal;
}

/** Virtual file system for `ls` / `cd` / `cat` */
type FSNode = { type: 'dir'; children: Record<string, FSNode> }
            | { type: 'file'; content: string };

/** Build a virtual FS from portfolio data */
function buildFS(): FSNode {
  const projects: Record<string, FSNode> = {};
  for (const p of data.projects) {
    projects[p.slug] = {
      type: 'file',
      content: [
        `\x1b[1;38;2;255;140;0m${p.name}\x1b[0m (${p.year})`,
        `  ${p.desc}`,
        `  Tech: ${p.tech.join(', ')}`,
        `  URL:  ${p.url}`,
      ].join('\r\n'),
    };
  }

  return {
    type: 'dir',
    children: {
      'about.txt': {
        type: 'file',
        content: data.about.join('\r\n'),
      },
      'skills.txt': {
        type: 'file',
        content: Object.entries(data.skills)
          .map(([cat, items]) => `\x1b[1;38;2;255;176;0m${cat}\x1b[0m: ${items.join(', ')}`)
          .join('\r\n'),
      },
      'contact.txt': {
        type: 'file',
        content: [
          `Email:    ${data.contact.email}`,
          `GitHub:   ${data.contact.github}`,
          `LinkedIn: ${data.contact.linkedin}`,
          data.contact.twitter ? `Twitter:  ${data.contact.twitter}` : '',
        ].filter(Boolean).join('\r\n'),
      },
      projects: {
        type: 'dir',
        children: projects,
      },
    },
  };
}

const fs = buildFS();
let cwd: string[] = []; // current working directory path segments

/** Resolve a path relative to cwd */
function resolve(path: string): FSNode | null {
  const parts = path === '~' || path === '/'
    ? []
    : path.startsWith('/')
      ? path.split('/').filter(Boolean)
      : [...cwd, ...path.split('/').filter(Boolean)];

  // Handle '..'
  const resolved: string[] = [];
  for (const p of parts) {
    if (p === '..') resolved.pop();
    else if (p !== '.') resolved.push(p);
  }

  let node: FSNode = fs;
  for (const seg of resolved) {
    if (node.type !== 'dir' || !(seg in node.children)) return null;
    node = node.children[seg];
  }
  return node;
}

/** Get the display path for prompt */
export function getCwd(): string {
  return cwd.length === 0 ? '~' : '~/' + cwd.join('/');
}

/* ── Command handlers ────────────────────────────────── */

const HELP_TEXT = [
  '',
  '\x1b[1;38;2;255;176;0m  Available Commands:\x1b[0m',
  '',
  '  \x1b[1;38;2;255;208;96mhelp\x1b[0m          Show this help message',
  '  \x1b[1;38;2;255;208;96mabout\x1b[0m         Who I am',
  '  \x1b[1;38;2;255;208;96mskills\x1b[0m        Technical skills',
  '  \x1b[1;38;2;255;208;96mprojects\x1b[0m      View my projects',
  '  \x1b[1;38;2;255;208;96mcontact\x1b[0m       Get in touch',
  '  \x1b[1;38;2;255;208;96mls\x1b[0m            List directory contents',
  '  \x1b[1;38;2;255;208;96mcd <dir>\x1b[0m      Change directory',
  '  \x1b[1;38;2;255;208;96mcat <file>\x1b[0m    Display file contents',
  '  \x1b[1;38;2;255;208;96mclear\x1b[0m         Clear the terminal',
  '  \x1b[1;38;2;255;208;96mreset\x1b[0m         Reset terminal to defaults',
  '  \x1b[1;38;2;255;208;96mtheme <name>\x1b[0m  Change color theme (amber, green)',
  '',
];

/**
 * Execute a command string and write output via the writer.
 *
 * @param input - Raw input string from the terminal
 * @param w     - TerminalWriter for output
 */
export function execute(input: string, w: TerminalWriter): void {
  const trimmed = input.trim();
  if (!trimmed) return;

  const parts = trimmed.split(/\s+/);
  const cmd = parts[0].toLowerCase();
  const args = parts.slice(1);

  switch (cmd) {
    /* ── help ─────────────────────────────────────────── */
    case 'help':
      HELP_TEXT.forEach(line => w.writeln(line));
      break;

    /* ── about ────────────────────────────────────────── */
    case 'about': {
      w.writeln('');
      w.writeln(`\x1b[1;38;2;255;140;0m  ${data.owner.name}\x1b[0m`);
      w.writeln(`  ${data.owner.title}`);
      w.writeln(`  ${data.owner.tagline}`);
      w.writeln(`  📍 ${data.owner.location}`);
      w.writeln('');
      data.about.forEach(line => w.writeln(`  ${line}`));
      w.writeln('');
      break;
    }

    /* ── skills ───────────────────────────────────────── */
    case 'skills': {
      w.writeln('');
      for (const [category, items] of Object.entries(data.skills)) {
        w.writeln(`  \x1b[1;38;2;255;176;0m${category}\x1b[0m`);
        w.writeln(`    ${items.join('  •  ')}`);
        w.writeln('');
      }
      break;
    }

    /* ── projects ─────────────────────────────────────── */
    case 'projects': {
      w.writeln('');
      for (const p of data.projects) {
        w.writeln(`  \x1b[1;38;2;255;140;0m${p.name}\x1b[0m \x1b[38;2;136;136;136m(${p.year})\x1b[0m`);
        w.writeln(`    ${p.desc}`);
        w.writeln(`    Tech: \x1b[38;2;255;208;96m${p.tech.join(', ')}\x1b[0m`);
        w.writeln('');
      }
      w.writeln(`  \x1b[38;2;136;136;136mType \x1b[1;38;2;255;208;96mcat projects/<slug>\x1b[0;38;2;136;136;136m for details.\x1b[0m`);
      w.writeln('');
      break;
    }

    /* ── contact ──────────────────────────────────────── */
    case 'contact': {
      w.writeln('');
      w.writeln(`  \x1b[1;38;2;255;176;0mContact\x1b[0m`);
      w.writeln(`    📧  ${data.contact.email}`);
      w.writeln(`    🐙  ${data.contact.github}`);
      w.writeln(`    💼  ${data.contact.linkedin}`);
      w.writeln('');
      break;
    }

    /* ── ls ────────────────────────────────────────────── */
    case 'ls': {
      const target = args[0] ? resolve(args[0]) : resolve('.');
      if (!target || target.type !== 'dir') {
        w.writeln(`ls: cannot access '${args[0] || '.'}': Not a directory`);
        break;
      }
      w.writeln('');
      for (const [name, node] of Object.entries(target.children)) {
        const suffix = node.type === 'dir' ? '/' : '';
        const color = node.type === 'dir' ? '\x1b[1;38;2;255;208;96m' : '\x1b[38;2;255;140;0m';
        w.writeln(`  ${color}${name}${suffix}\x1b[0m`);
      }
      w.writeln('');
      break;
    }

    /* ── cd ────────────────────────────────────────────── */
    case 'cd': {
      const path = args[0] || '~';
      if (path === '~' || path === '/') {
        cwd = [];
        break;
      }
      const target = resolve(path);
      if (!target || target.type !== 'dir') {
        w.writeln(`cd: no such directory: ${path}`);
        break;
      }
      // Recompute cwd from path
      if (path.startsWith('/')) {
        cwd = path.split('/').filter(Boolean);
      } else {
        const newCwd = [...cwd, ...path.split('/').filter(Boolean)];
        const resolved: string[] = [];
        for (const p of newCwd) {
          if (p === '..') resolved.pop();
          else if (p !== '.') resolved.push(p);
        }
        cwd = resolved;
      }
      break;
    }

    /* ── cat ───────────────────────────────────────────── */
    case 'cat': {
      if (!args[0]) {
        w.writeln('cat: missing file argument');
        break;
      }
      const target = resolve(args[0]);
      if (!target) {
        w.writeln(`cat: ${args[0]}: No such file or directory`);
        break;
      }
      if (target.type === 'dir') {
        w.writeln(`cat: ${args[0]}: Is a directory`);
        break;
      }
      w.writeln('');
      target.content.split('\r\n').forEach(line => w.writeln(`  ${line}`));
      w.writeln('');
      break;
    }

    /* ── clear ─────────────────────────────────────────── */
    case 'clear':
      w.clear();
      break;

    /* ── reset ─────────────────────────────────────────── */
    case 'reset':
      w.clear();
      cwd = [];
      w.terminal.options.theme = themes.amber;
      w.writeln('\x1b[38;2;0;230;118mTerminal reset.\x1b[0m');
      w.writeln('');
      break;

    /* ── theme ─────────────────────────────────────────── */
    case 'theme': {
      const name = args[0]?.toLowerCase();
      if (!name || !themes[name]) {
        w.writeln(`Available themes: ${Object.keys(themes).join(', ')}`);
        break;
      }
      w.terminal.options.theme = themes[name];
      w.writeln(`\x1b[38;2;0;230;118mTheme changed to '${name}'.\x1b[0m`);
      w.writeln('');
      break;
    }

    /* ── unknown command ──────────────────────────────── */
    default:
      w.writeln(`\x1b[38;2;255;68;68mCommand not found: ${cmd}\x1b[0m`);
      w.writeln(`Type \x1b[1;38;2;255;208;96mhelp\x1b[0m to see available commands.`);
      w.writeln('');
      break;
  }
}

/**
 * Get all command names for tab completion.
 * Includes both builtin commands and virtual FS entries.
 */
export function getCompletions(partial: string): string[] {
  const allCommands = [...config.commands, 'theme'];
  return allCommands.filter(c => c.startsWith(partial.toLowerCase()));
}

