/**
 * ─────────────────────────────────────────────────────
 *  BootOverlay.tsx — React island for the BIOS boot sequence
 *
 *  Displays boot lines one-by-one with a typewriter effect,
 *  interpolating config values (owner name, hostname).
 *  After the last line, calls the onComplete callback so
 *  the page can transition to the terminal.
 *
 *  Usage in Astro:
 *    <BootOverlay client:load onComplete={() => { ... }} />
 * ─────────────────────────────────────────────────────
 */

import { useEffect, useRef, useState, useCallback } from 'react';
import { config } from '../terminal/config';

/* ── Boot line definition ────────────────────────────── */

/** A single boot sequence line with styling class */
interface BootLine {
  /** Text content (may contain {{owner}} or {{host}} tokens) */
  text: string;
  /** CSS class for coloring: 'ok' | 'dim' | 'info' | '' */
  cls: string;
}

/** Boot sequence lines — mirrors the legacy boot.js */
const BOOT_LINES: BootLine[] = [
  { text: 'BIOS v2.1 — Detecting hardware...',                cls: 'dim'  },
  { text: '[  OK  ] CPU: x86_64 cortex-A72 @ 2.4GHz',        cls: 'ok'   },
  { text: '[  OK  ] RAM: 16 GB DDR4',                          cls: 'ok'   },
  { text: '[  OK  ] Display: Amber CRT 680×440',               cls: 'ok'   },
  { text: '[  OK  ] Keyboard: Model M (vintage)',               cls: 'ok'   },
  { text: '',                                                    cls: ''     },
  { text: 'Loading CLI-OS kernel v4.2...',                      cls: 'info' },
  { text: `[  OK  ] Mounting /home/${config.owner.toLowerCase().replace(/\s+/g, '')}`, cls: 'ok' },
  { text: '[  OK  ] Importing skill-set modules...',            cls: 'ok'   },
  { text: `[  OK  ] Starting virtual host: ${config.host}`,    cls: 'ok'   },
  { text: '[  OK  ] Activating CRT scanline driver',            cls: 'ok'   },
  { text: '[  OK  ] Injecting personality matrix...',           cls: 'ok'   },
  { text: '[  OK  ] Spawning AI assistant (Ezra)',              cls: 'ok'   },
  { text: '',                                                    cls: ''     },
  { text: '[[  OK  ]] System ready.',                           cls: 'ok'   },
];

/* ── Props ───────────────────────────────────────────── */

/** @interface BootOverlayProps */
export interface BootOverlayProps {
  /**
   * Called when the boot sequence is complete.
   * The page should use this to open the lid and show the terminal.
   */
  onComplete: () => void;
}

/* ── Component ───────────────────────────────────────── */

/**
 * BootOverlay — Full-screen typewriter boot sequence.
 *
 * Renders inside the CRT wrapper and fades out when done.
 * Uses requestAnimationFrame-based timing for smooth typing.
 */
export default function BootOverlay({ onComplete }: BootOverlayProps) {
  /** Ref to the overlay container for direct DOM writes (perf) */
  const overlayRef = useRef<HTMLDivElement>(null);

  /** Track whether the boot is active for CSS class */
  const [active, setActive] = useState(false);

  /**
   * Type a single character at a time into a <span>.
   * Uses rAF + timestamp for consistent timing regardless of frame rate.
   */
  const typewriteLine = useCallback(
    (container: HTMLDivElement, line: BootLine): Promise<void> => {
      return new Promise((resolve) => {
        const span = document.createElement('span');
        span.className = line.cls || '';
        container.appendChild(span);
        container.appendChild(document.createTextNode('\n'));

        const text = line.text;

        // Blank lines resolve immediately
        if (!text) {
          resolve();
          return;
        }

        let charIndex = 0;
        let lastTime = 0;

        const step = (timestamp: number) => {
          if (!lastTime) lastTime = timestamp;
          const elapsed = timestamp - lastTime;

          // Type one character every ~config.typeSpeed ms
          if (elapsed >= config.typeSpeed) {
            span.textContent += text[charIndex] || '';
            charIndex++;
            lastTime = timestamp;
          }

          if (charIndex < text.length) {
            requestAnimationFrame(step);
          } else {
            resolve();
          }
        };

        requestAnimationFrame(step);
      });
    },
    []
  );

  /**
   * Run the entire boot sequence:
   * 1. Show overlay
   * 2. Small initial pause
   * 3. Type each line with inter-line delay
   * 4. Post-boot pause
   * 5. Hide overlay and call onComplete
   */
  useEffect(() => {
    const overlay = overlayRef.current;
    if (!overlay) return;

    let cancelled = false;

    const sleep = (ms: number) =>
      new Promise<void>((res) => {
        const id = setTimeout(res, ms);
        // Store timeout id for potential cleanup
        if (cancelled) clearTimeout(id);
      });

    async function runBoot() {
      // Activate the overlay (fade in)
      setActive(true);

      // Small pre-boot pause
      await sleep(400);

      // Type each boot line
      for (const line of BOOT_LINES) {
        if (cancelled) return;
        await typewriteLine(overlay, line);
        await sleep(config.bootLineDelay);
      }

      // Post-boot hold so user can read "System ready"
      await sleep(600);

      if (cancelled) return;

      // Deactivate overlay (fade out)
      setActive(false);

      // Wait for CSS fade-out transition (500ms in boot.css)
      await sleep(550);

      // Signal completion to parent
      onComplete();
    }

    runBoot();

    // Cleanup on unmount
    return () => {
      cancelled = true;
    };
  }, [onComplete, typewriteLine]);

  return (
    <div
      ref={overlayRef}
      className={`boot-overlay${active ? ' active' : ''}`}
      role="status"
      aria-live="polite"
      aria-label="System boot sequence"
    />
  );
}

/**
 * ─────────────────────────────────────────────────────
 *  Terminal.tsx — Main React island wrapping xterm.js
 *
 *  Initializes an xterm.Terminal inside a DOM ref, loads
 *  FitAddon and WebLinksAddon, manages input buffering,
 *  command history, tab completion, and dispatches to
 *  the command interpreter.
 *
 *  Usage in Astro:
 *    <Terminal client:load onBoot={() => { ... }} />
 * ─────────────────────────────────────────────────────
 */

import { useEffect, useRef, useCallback } from 'react';
import { Terminal as XTerm } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import '@xterm/xterm/css/xterm.css';

import { config } from '../terminal/config';
import { amberTheme } from '../terminal/themes';
import { execute, getCompletions, getCwd } from '../terminal/commands';
import type { TerminalWriter } from '../terminal/commands';

/* ── ASCII art banner (hardcoded, no figlet library) ── */
const BANNER = [
  '     ██╗ ██████╗ ███████╗██╗     ',
  '     ██║██╔═══██╗██╔════╝██║     ',
  '     ██║██║   ██║█████╗  ██║     ',
  '██   ██║██║   ██║██╔══╝  ██║     ',
  '╚█████╔╝╚██████╔╝███████╗███████╗',
  ' ╚════╝  ╚═════╝ ╚══════╝╚══════╝',
];

/** Maximum command history entries */
const MAX_HISTORY = 80;

/* ── Props ───────────────────────────────────────────── */

/** @interface TerminalProps */
export interface TerminalProps {
  /**
   * Called once the terminal is mounted and ready.
   * The page can use this to know the terminal is interactive.
   */
  onBoot?: () => void;

  /** Additional CSS class name for the mount container */
  className?: string;
}

/* ── Helpers ─────────────────────────────────────────── */

/**
 * Build the prompt string with ANSI colors.
 * Format: joel@portfolio:~$
 */
function buildPrompt(): string {
  const cwdPath = getCwd();
  return `\x1b[1;38;2;255;140;0m${config.handle.toLowerCase()}@${config.host}\x1b[0m:\x1b[38;2;255;208;96m${cwdPath}\x1b[0m$ `;
}

/**
 * Get a seasonal greeting based on current date.
 * Mirrors the legacy Easter.timeGreeting() function.
 */
function getSeasonalGreeting(): string | null {
  const now = new Date();
  const month = now.getMonth() + 1; // 1-indexed
  const day = now.getDate();
  const hour = now.getHours();

  // Time-based greetings
  if (hour >= 5 && hour < 12) {
    return '☀️  Good morning! Ready to explore?';
  } else if (hour >= 12 && hour < 17) {
    return '🌤️  Good afternoon! Welcome aboard.';
  } else if (hour >= 17 && hour < 21) {
    return '🌅  Good evening! Nice to see you.';
  } else {
    return '🌙  Burning the midnight oil? Respect.';
  }
}

/* ── Component ───────────────────────────────────────── */

/**
 * Terminal — Full xterm.js terminal island.
 *
 * Handles:
 * - xterm initialization with amber CRT theme
 * - FitAddon for responsive resizing
 * - WebLinksAddon for clickable URLs
 * - Keystroke buffering, Enter, Backspace, arrows
 * - Command history (up/down, max 80 entries)
 * - Tab completion from command list
 * - FIGlet banner, welcome message, seasonal greeting
 * - Command dispatch to commands.ts interpreter
 */
export default function Terminal({ onBoot, className }: TerminalProps) {
  /** Ref for the DOM element where xterm mounts */
  const mountRef = useRef<HTMLDivElement>(null);

  /** Ref to persist the xterm instance across renders */
  const termRef = useRef<XTerm | null>(null);

  /**
   * Initialize xterm.js in useEffect (requires DOM).
   * Clean up on unmount.
   */
  useEffect(() => {
    const container = mountRef.current;
    if (!container) return;

    /* ── Create terminal instance ───────────────────── */
    const term = new XTerm({
      theme: amberTheme,
      fontFamily: "'Share Tech Mono', 'JetBrains Mono', 'Courier New', monospace",
      fontSize: 14,
      lineHeight: 1.3,
      cursorBlink: true,
      cursorStyle: 'block',
      allowTransparency: true,
      scrollback: 1000,
      convertEol: true,
    });

    termRef.current = term;

    /* ── Load addons ────────────────────────────────── */
    const fitAddon = new FitAddon();
    term.loadAddon(fitAddon);
    term.loadAddon(new WebLinksAddon());

    /* ── Mount to DOM ───────────────────────────────── */
    term.open(container);

    // Initial fit (slight delay to ensure container has dimensions)
    requestAnimationFrame(() => {
      fitAddon.fit();
    });

    /* ── Resize handler ─────────────────────────────── */
    const handleResize = () => {
      fitAddon.fit();
    };
    window.addEventListener('resize', handleResize);

    /* ── Input state ────────────────────────────────── */
    let inputBuffer = '';
    const history: string[] = [];
    let historyIndex = -1;
    let savedInput = ''; // save current input when browsing history

    /* ── Terminal writer for commands ────────────────── */
    const writer: TerminalWriter = {
      writeln: (text: string) => term.writeln(text),
      write: (text: string) => term.write(text),
      clear: () => {
        term.clear();
        term.write('\x1b[H'); // move cursor to top-left
      },
      terminal: term,
    };

    /* ── Print banner & welcome ─────────────────────── */
    term.writeln('');
    BANNER.forEach((line) => {
      term.writeln(`\x1b[38;2;255;102;0m${line}\x1b[0m`);
    });
    term.writeln('');
    term.writeln(`\x1b[1;38;2;255;176;0mWelcome to ${config.owner}'s CLI Portfolio\x1b[0m`);
    term.writeln(`\x1b[38;2;136;136;136mType \x1b[1;38;2;255;208;96mhelp\x1b[0;38;2;136;136;136m to see available commands.\x1b[0m`);

    // Seasonal greeting
    const greeting = getSeasonalGreeting();
    if (greeting) {
      term.writeln(`\x1b[38;2;0;230;118m${greeting}\x1b[0m`);
    }

    term.writeln('');

    // Write initial prompt
    term.write(buildPrompt());

    /* ── Clear the current line and rewrite ──────────── */
    function clearLine() {
      // Move to start of prompt, clear to end
      term.write('\r\x1b[K');
      term.write(buildPrompt());
    }

    /* ── Key handler ────────────────────────────────── */
    term.onData((data: string) => {
      const code = data.charCodeAt(0);

      // ── Enter (CR or LF) ─────────────────────────
      if (data === '\r' || data === '\n') {
        term.writeln('');

        const trimmed = inputBuffer.trim();
        if (trimmed) {
          // Add to history (deduplicate consecutive)
          if (history.length === 0 || history[history.length - 1] !== trimmed) {
            history.push(trimmed);
            if (history.length > MAX_HISTORY) history.shift();
          }

          // Execute command
          execute(trimmed, writer);
        }

        // Reset state
        inputBuffer = '';
        historyIndex = -1;
        savedInput = '';

        // Print new prompt
        term.write(buildPrompt());
        return;
      }

      // ── Backspace (127 or \b) ─────────────────────
      if (code === 127 || data === '\b') {
        if (inputBuffer.length > 0) {
          inputBuffer = inputBuffer.slice(0, -1);
          // Move cursor back, write space, move back again
          term.write('\b \b');
        }
        return;
      }

      // ── Tab (completion) ──────────────────────────
      if (data === '\t') {
        const parts = inputBuffer.split(/\s+/);
        const partial = parts[parts.length - 1];

        if (partial) {
          const completions = getCompletions(partial);
          if (completions.length === 1) {
            // Complete the word
            const suffix = completions[0].slice(partial.length);
            inputBuffer += suffix + ' ';
            term.write(suffix + ' ');
          } else if (completions.length > 1) {
            // Show options
            term.writeln('');
            term.writeln(completions.join('  '));
            term.write(buildPrompt() + inputBuffer);
          }
        }
        return;
      }

      // ── Arrow keys (escape sequences) ─────────────
      if (data.startsWith('\x1b[')) {
        const arrow = data.slice(2);

        // Up arrow — previous history
        if (arrow === 'A') {
          if (history.length === 0) return;

          // Save current input on first press
          if (historyIndex === -1) {
            savedInput = inputBuffer;
            historyIndex = history.length;
          }

          if (historyIndex > 0) {
            historyIndex--;
            inputBuffer = history[historyIndex];
            clearLine();
            term.write(inputBuffer);
          }
          return;
        }

        // Down arrow — next history
        if (arrow === 'B') {
          if (historyIndex === -1) return;

          historyIndex++;
          if (historyIndex >= history.length) {
            // Back to saved input
            historyIndex = -1;
            inputBuffer = savedInput;
            savedInput = '';
          } else {
            inputBuffer = history[historyIndex];
          }
          clearLine();
          term.write(inputBuffer);
          return;
        }

        // Left/Right arrows — ignore for now (no cursor movement)
        return;
      }

      // ── Ctrl+C ────────────────────────────────────
      if (code === 3) {
        term.writeln('^C');
        inputBuffer = '';
        historyIndex = -1;
        term.write(buildPrompt());
        return;
      }

      // ── Ctrl+L (clear screen) ────────────────────
      if (code === 12) {
        writer.clear();
        term.write(buildPrompt() + inputBuffer);
        return;
      }

      // ── Regular printable characters ──────────────
      if (code >= 32) {
        inputBuffer += data;
        term.write(data);
      }
    });

    /* ── Focus terminal on click ────────────────────── */
    container.addEventListener('click', () => {
      term.focus();
    });

    /* ── Signal boot complete ───────────────────────── */
    if (onBoot) {
      onBoot();
    }

    /* ── Cleanup on unmount ─────────────────────────── */
    return () => {
      window.removeEventListener('resize', handleResize);
      term.dispose();
      termRef.current = null;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div
      ref={mountRef}
      id="terminal-mount"
      className={className || ''}
      role="application"
      aria-label="Interactive CLI terminal"
    />
  );
}

/**
 * ─────────────────────────────────────────────────────
 *  AudioBar.tsx — React island for ambient audio controls
 *
 *  A simple play/pause toggle for background ambient audio.
 *  Uses the HTML5 Audio API with graceful autoplay handling.
 *  Renders as a fixed-position button in the bottom-right.
 *
 *  Usage in Astro:
 *    <AudioBar client:idle />
 * ─────────────────────────────────────────────────────
 */

import { useRef, useState, useCallback, useEffect } from 'react';
import { config } from '../terminal/config';

/* ── Props ───────────────────────────────────────────── */

/**
 * AudioBar has no required props.
 * Audio source and volume are pulled from config.
 */

/* ── Component ───────────────────────────────────────── */

/**
 * AudioBar — Fixed-position ambient audio toggle.
 *
 * Features:
 * - Plays /sounds/ambient.mp3 in a loop at low volume
 * - Gracefully handles autoplay restrictions (waits for
 *   first user interaction to start playback)
 * - Emoji toggle: 🔊 (playing) / 🔇 (muted)
 * - Fixed to bottom-right corner
 */
export default function AudioBar() {
  /** HTML Audio element ref */
  const audioRef = useRef<HTMLAudioElement | null>(null);

  /** Whether the audio is currently muted/paused */
  const [muted, setMuted] = useState(true);

  /** Whether audio has been initialized */
  const initRef = useRef(false);

  /**
   * Lazily create the Audio element on first interaction.
   * This avoids creating it during SSR or before user gesture.
   */
  const getAudio = useCallback((): HTMLAudioElement | null => {
    if (audioRef.current) return audioRef.current;

    try {
      const audio = new Audio(config.audioSrc);
      audio.loop = true;
      audio.volume = config.audioVol;
      audioRef.current = audio;
      return audio;
    } catch {
      console.warn('[AudioBar] Failed to create Audio element');
      return null;
    }
  }, []);

  /**
   * Toggle play/pause.
   * On first click, creates the Audio element and starts playback.
   */
  const toggle = useCallback(() => {
    const audio = getAudio();
    if (!audio) return;

    if (muted) {
      // Try to play — may be blocked by autoplay policy
      audio.play().catch(() => {
        // Autoplay blocked: will retry on next interaction
        console.info('[AudioBar] Autoplay blocked, will retry on next click');
      });
      setMuted(false);
    } else {
      audio.pause();
      setMuted(true);
    }
  }, [muted, getAudio]);

  /**
   * Attempt to auto-start audio after user's first interaction
   * with the page (keydown or click anywhere).
   */
  useEffect(() => {
    if (initRef.current) return;
    initRef.current = true;

    const startOnInteraction = () => {
      const audio = getAudio();
      if (audio && muted) {
        audio.play().then(() => {
          setMuted(false);
        }).catch(() => {
          // Still blocked, user must click the button
        });
      }
      // Remove listeners after first attempt
      document.removeEventListener('keydown', startOnInteraction);
      document.removeEventListener('click', startOnInteraction);
    };

    document.addEventListener('keydown', startOnInteraction, { once: true });
    document.addEventListener('click', startOnInteraction, { once: true });

    return () => {
      document.removeEventListener('keydown', startOnInteraction);
      document.removeEventListener('click', startOnInteraction);
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  /**
   * Cleanup: pause audio on unmount
   */
  useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  return (
    <div
      id="audio-bar"
      role="region"
      aria-label="Audio controls"
      style={{
        position: 'fixed',
        bottom: '16px',
        right: '16px',
        zIndex: 100,
      }}
    >
      <button
        onClick={toggle}
        aria-label={muted ? 'Unmute ambient sound' : 'Mute ambient sound'}
        style={{
          background: 'rgba(26, 26, 26, 0.8)',
          border: '1px solid rgba(255, 140, 0, 0.3)',
          borderRadius: '8px',
          padding: '8px 12px',
          cursor: 'pointer',
          fontSize: '1.25rem',
          lineHeight: 1,
          transition: 'border-color 0.2s ease',
        }}
        title={muted ? 'Play ambient sound' : 'Mute ambient sound'}
      >
        <span aria-hidden="true">{muted ? '🔇' : '🔊'}</span>
      </button>
    </div>
  );
}

