/**
 * ─────────────────────────────────────────────────────
 *  index.astro — Main page for Joel's CLI Portfolio
 *
 *  Composition order:
 *    Layout
 *      └─ Skip Link (accessibility)
 *      └─ LaptopShell (3D frame)
 *           └─ CRTScreen (effects wrapper)
 *                ├─ BootOverlay (client:load — typewriter boot)
 *                └─ Terminal (client:load — xterm.js island)
 *      └─ AudioBar (client:idle — ambient audio toggle)
 *
 *  Boot flow:
 *    1. Page loads → BootOverlay starts typewriting
 *    2. BootOverlay completes → lid opens (#lid.open)
 *    3. Lid animation ends → terminal fades in (visible class)
 *    4. AudioBar initializes lazily in background
 * ─────────────────────────────────────────────────────
 */

import Layout from '../layouts/Layout.astro';
import LaptopShell from '../components/LaptopShell.astro';
import CRTScreen from '../components/CRTScreen.astro';
import BootOverlay from '../components/BootOverlay.tsx';
import Terminal from '../components/Terminal.tsx';
import AudioBar from '../components/AudioBar.tsx';
---

<Layout>
  <!-- ── Accessibility Skip Link ───────────────────── -->
  <a href="#terminal-mount" class="skip-link">Skip to terminal</a>

  <!-- ── 3D Laptop Shell ───────────────────────────── -->
  <LaptopShell>
    <!-- ── CRT Effects Wrapper ───────────────────── -->
    <CRTScreen>
      <!--
        Boot Overlay (React island — client:load)
        Shows immediately, typewriter boot sequence,
        then calls window.__bootComplete() when done.
      -->
      <BootOverlay
        client:load
        onComplete="window.__bootComplete()"
      />

      <!--
        Terminal (React island — client:load)
        Starts hidden; made visible after boot completes.
        onBoot fires when xterm is initialized and ready.
      -->
      <Terminal client:load />
    </CRTScreen>
  </LaptopShell>

  <!-- ── Audio Controls (React island — client:idle) ── -->
  <AudioBar client:idle />

  <!--
    ── Boot Flow Controller ─────────────────────────
    Minimal vanilla JS that coordinates the boot sequence:
    1. BootOverlay typewriters boot lines
    2. On complete → open laptop lid (CSS animation)
    3. On lid open → fade in terminal
    This script is inline because it's <20 lines of glue.
  -->
  <script>
    /**
     * Boot sequence coordinator.
     * BootOverlay calls window.__bootComplete() when done.
     * This script adds .open to #lid and .visible to #terminal-mount.
     */
    (function () {
      // Called by BootOverlay's onComplete prop
      window.__bootComplete = function () {
        const lid = document.getElementById('lid');
        const termMount = document.getElementById('terminal-mount');

        if (!lid || !termMount) return;

        // Step 1: Open the lid (CSS animation in laptop.css)
        lid.classList.add('open');

        // Step 2: After lid animation, show the terminal
        lid.addEventListener(
          'animationend',
          () => {
            termMount.classList.add('visible');

            // Focus the terminal for keyboard input
            const xtermEl = termMount.querySelector('.xterm-helper-textarea') as HTMLTextAreaElement | null;
            if (xtermEl) xtermEl.focus();
          },
          { once: true }
        );
      };
    })();
  </script>
</Layout>

