20: import { CONFIG } from './config';
21: import { loadPortfolioData, loadSystemPrompt, buildPortfolioContext } from './data';
22: 
23: // ── Types ─────────────────────────────────────────────────────────
24: 
25: interface ChatMessage {
26:   role: 'system' | 'user' | 'assistant';
27:   content: string;
28: }
29: 
30: interface MiMoResponse {
31:   choices: Array<{
32:     message: {
33:       content: string;
34:     };
35:   }>;
