54:  *
55:  * @param writer - Terminal writer for output
56:  */
57: export async function startChat(writer: TerminalWriter): Promise<void> {
58:   if (_active) {
59:     writer.writeln('\x1b[38;2;136;136;136mEzra is already running. Type "exit" to close.\x1b[0m');
60:     return;
61:   }
62: 
63:   _active = true;
64:   _history = [];
65: 
66:   // Build system prompt with portfolio context
67:   try {
68:     const [systemPrompt, data] = await Promise.all([
69:       loadSystemPrompt(),
70:       loadPortfolioData(),
71:     ]);
72:     const context = buildPortfolioContext(data);
73:     _systemMessage = `${systemPrompt}\n\n${context}`;
74:   } catch {
75:     _systemMessage = 'You are Ezra, a helpful AI assistant for Joel Alfred Israel\'s portfolio.';
76:   }
77: 
78:   writer.writeln('');
79:   writer.writeln('\x1b[1;38;2;0;229;255mEzra v2.0 — AI Assistant\x1b[0m');
80:   writer.writeln('\x1b[38;2;136;136;136mPowered by Xiaomi MiMo. Type your message. Type "exit" to return to shell.\x1b[0m');
81:   writer.writeln('');
