138:     { role: 'system', content: _systemMessage },
139:     ..._history,
140:   ];
141: 
142:   const body = {
143:     model: CONFIG.mimoModel,
144:     max_tokens: CONFIG.mimoMaxTokens,
145:     messages,
146:   };
147: 
148:   const res = await fetch(CONFIG.mimoEndpoint, {
149:     method: 'POST',
150:     headers: {
151:       'Content-Type': 'application/json',
152:       'Authorization': `Bearer ${CONFIG.mimoApiKey}`,
153:     },
154:     body: JSON.stringify(body),
155:   });
156: 
157:   if (!res.ok) {
158:     const errBody = await res.json().catch(() => ({}));
159:     const errMsg = (errBody as Record<string, unknown>)?.error
160:       ? JSON.stringify((errBody as Record<string, unknown>).error)
161:       : res.statusText;
162:     throw new Error(errMsg);
163:   }
164: 
165:   const data = (await res.json()) as MiMoResponse;
166:   const reply = data.choices?.[0]?.message?.content ?? '(no response)';
167: 
168:   // Add to history for multi-turn
169:   _history.push({ role: 'assistant', content: reply });
170: 
171:   return reply;
172: }
