1: /**
2:  * @fileoverview Snake mini-game (Canvas-based).
3:  *
4:  * Renders a snake game on a canvas overlay inside the terminal area.
5:  * Press arrow keys to steer, Q to quit.
6:  *
7:  * @module snake
8:  */
9: 
10: // ── Constants ─────────────────────────────────────────────────────
11: 
12: const TILE = 16;
13: const W = 26;   // tiles wide
14: const H = 20;   // tiles tall
15: const DELAY = 110; // ms per tick
16: 
17: // ── State ─────────────────────────────────────────────────────────
18: 
19: let canvas: HTMLCanvasElement | null = null;
20: let ctx: CanvasRenderingContext2D | null = null;
21: let running = false;
22: let timer: ReturnType<typeof setTimeout> | null = null;
23: let dir = { x: 1, y: 0 };
24: let nextDir = { x: 1, y: 0 };
25: let body: Array<{ x: number; y: number }> = [];
26: let food = { x: 0, y: 0 };
27: let score = 0;
28: let _onQuit: (() => void) | null = null;
29: 
30: // ── Keyboard Handler ──────────────────────────────────────────────
31: 
32: function onKey(e: KeyboardEvent): void {
33:   const map: Record<string, { x: number; y: number }> = {
34:     ArrowUp:    { x: 0, y: -1 },
35:     ArrowDown:  { x: 0, y: 1 },
36:     ArrowLeft:  { x: -1, y: 0 },
37:     ArrowRight: { x: 1, y: 0 },
38:   };
39: 
40:   if (map[e.key] && !(dir.x === -map[e.key].x && dir.y === -map[e.key].y)) {
41:     nextDir = map[e.key];
42:     e.preventDefault();
43:   }
44: 
45:   if (e.key === 'q' || e.key === 'Q') {
46:     cleanup();
47:   }
48: }
49: 
50: // ── Game Logic ────────────────────────────────────────────────────
51: 
52: function spawnFood(): void {
53:   do {
54:     food = {
55:       x: Math.floor(Math.random() * W),
56:       y: Math.floor(Math.random() * H),
57:     };
58:   } while (body.some(s => s.x === food.x && s.y === food.y));
59: }
60: 
61: function resetGame(): void {
62:   dir = { x: 1, y: 0 };
63:   nextDir = { x: 1, y: 0 };
64:   body = [{ x: 13, y: 10 }, { x: 12, y: 10 }, { x: 11, y: 10 }];
65:   score = 0;
66:   spawnFood();
67:   draw();
68: }
69: 
70: function tick(): void {
71:   if (!running) return;
72:   dir = nextDir;
73: 
74:   const head = {
75:     x: (body[0].x + dir.x + W) % W,
76:     y: (body[0].y + dir.y + H) % H,
77:   };
78: 
79:   // Self-collision
80:   if (body.some(s => s.x === head.x && s.y === head.y)) {
81:     gameOver();
82:     return;
83:   }
84: 
85:   body.unshift(head);
86: 
87:   if (head.x === food.x && head.y === food.y) {
88:     score++;
89:     spawnFood();
90:   } else {
91:     body.pop();
92:   }
93: 
94:   draw();
95:   timer = setTimeout(tick, DELAY);
96: }
97: 
98: function draw(): void {
99:   if (!ctx || !canvas) return;
100: 
101:   ctx.fillStyle = '#000';
102:   ctx.fillRect(0, 0, canvas.width, canvas.height);
103: 
104:   // Grid dots
105:   ctx.fillStyle = '#1a0a00';
106:   for (let x = 0; x < W; x++) {
107:     for (let y = 0; y < H; y++) {
108:       ctx.fillRect(x * TILE + 7, y * TILE + 7, 2, 2);
109:     }
110:   }
111: 
112:   // Food
113:   ctx.fillStyle = '#ff5500';
114:   ctx.shadowColor = '#ff5500';
115:   ctx.shadowBlur = 8;
116:   ctx.fillRect(food.x * TILE + 2, food.y * TILE + 2, TILE - 4, TILE - 4);
117:   ctx.shadowBlur = 0;
118: 
119:   // Snake body with gradient
120:   body.forEach((seg, i) => {
121:     const t = 1 - (i / body.length) * 0.5;
122:     ctx!.fillStyle = `rgba(255,${Math.floor(176 * t)},0,1)`;
123:     ctx!.fillRect(seg.x * TILE + 1, seg.y * TILE + 1, TILE - 2, TILE - 2);
124:   });
125: 
126:   // Score
127:   ctx.fillStyle = '#ffb000';
128:   ctx.font = '11px monospace';
129:   ctx.fillText(`SCORE: ${score}`, 6, 14);
130: }
131: 
132: function gameOver(): void {
133:   running = false;
134:   if (!ctx || !canvas) return;
135: 
136:   ctx.fillStyle = 'rgba(0,0,0,0.7)';
137:   ctx.fillRect(0, 0, canvas.width, canvas.height);
138:   ctx.fillStyle = '#ff5500';
139:   ctx.font = 'bold 20px monospace';
140:   ctx.textAlign = 'center';
141:   ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 10);
142:   ctx.fillStyle = '#ffb000';
143:   ctx.font = '13px monospace';
144:   ctx.fillText(`Score: ${score}`, canvas.width / 2, canvas.height / 2 + 14);
145:   ctx.fillText('Press Q to exit', canvas.width / 2, canvas.height / 2 + 34);
146:   ctx.textAlign = 'left';
147: }
148: 
149: // ── Public API ────────────────────────────────────────────────────
150: 
151: /**
152:  * Launch the snake game inside a container element.
153:  *
154:  * @param container - DOM element to append the canvas to
155:  * @param onQuit - Callback when the game is closed
156:  */
157: export function launchSnake(container: HTMLElement, onQuit?: () => void): void {
158:   _onQuit = onQuit ?? null;
159:   running = false;
160: 
161:   // Create canvas
162:   canvas = document.createElement('canvas');
163:   canvas.width = W * TILE;
164:   canvas.height = H * TILE;
165:   canvas.style.cssText = `
166:     position: absolute; top: 50%; left: 50%;
167:     transform: translate(-50%, -50%);
168:     z-index: 50; border: 2px solid #ffb000;
169:     background: #000; image-rendering: pixelated;
170:   `;
171:   canvas.setAttribute('aria-label', 'Snake game');
172: 
173:   ctx = canvas.getContext('2d');
174:   container.appendChild(canvas);
175: 
176:   document.addEventListener('keydown', onKey);
177:   resetGame();
178:   running = true;
179:   timer = setTimeout(tick, DELAY);
180: }
181: 
182: /**
183:  * Clean up the snake game — remove canvas, listeners, timers.
184:  */
185: export function cleanup(): void {
186:   running = false;
187:   if (timer) clearTimeout(timer);
188:   document.removeEventListener('keydown', onKey);
189:   if (canvas?.parentNode) canvas.parentNode.removeChild(canvas);
190:   canvas = null;
191:   ctx = null;
192:   _onQuit?.();
193: }
