/**
 * ─────────────────────────────────────────────────────
 *  config.ts — Centralized configuration for the portfolio
 *
 *  All tuneable values live here. Logic files import
 *  this module instead of reaching for global state.
 *
 *  IMPORTANT: Exported as both `CONFIG` (for existing modules
 *  like chatbot.ts, neofetch.ts) and `config` (for new components).
 * ─────────────────────────────────────────────────────
 */

/** Portfolio site configuration */
export const CONFIG = {
  /** Owner's full name */
  owner: 'Joel Alfred Israel',

  /** Username / handle */
  handle: 'Joel01010',

  /** Virtual hostname */
  host: 'portfolio',

  /** Delay (ms) between boot lines */
  bootLineDelay: 55,

  /** Typewriter speed (ms per character) during boot */
  typeSpeed: 12,

  /** Ambient audio source path (relative to /public) */
  audioSrc: '/sounds/ambient.mp3',

  /** Default audio volume (0–1) */
  audioVol: 0.18,

  /** Chatbot name displayed in terminal */
  botName: 'ezra',

  /** Xiaomi MiMo API endpoint */
  mimoEndpoint: 'https://api.mimo.ai/v1/chat/completions',

  /** Xiaomi MiMo model name */
  mimoModel: 'mimo-7b',

  /** Xiaomi MiMo API key (should be set via env var in production) */
  mimoApiKey: '',

  /** Max tokens for AI responses */
  mimoMaxTokens: 300,

  /** Tab-completable command names */
  commands: [
    'help', 'ls', 'cd', 'cat', 'clear', 'about',
    'skills', 'projects', 'contact', 'ezra', 'snake',
    'neofetch', 'theme', 'reset',
  ] as const,
} as const;

/**
 * Alias for backwards compatibility — new components can use either.
 * @deprecated Prefer `CONFIG` for consistency with existing modules.
 */
export const config = CONFIG;

/** Type alias for valid command names */
export type CommandName = (typeof CONFIG.commands)[number];

/**
 * ─────────────────────────────────────────────────────
 *  commands.ts — Command interpreter for the xterm terminal
 *
 *  Central dispatcher that routes command strings to their
 *  handlers. Integrates with existing modules:
 *  - filesystem.ts for ls/cd/cat
 *  - neofetch.ts for neofetch display
 *  - chatbot.ts for ezra AI
 *  - snake.ts for the snake mini-game
 *  - themes.ts for theme switching
 *
 *  Exposes `execute()` and `getCompletions()` for Terminal.tsx.
 * ─────────────────────────────────────────────────────
 */

import portfolioData from '../data/portfolio.json';
import type { PortfolioData, TerminalWriter as ITerminalWriter } from './types';
import { CONFIG } from './config';
import { themes, getAllThemeKeys } from './themes';
import {
  initFilesystem, getCwd as fsCwd, ls, cd, cat,
} from './filesystem';
import { renderNeofetch } from './neofetch';
import { startChat, handleInput, isActive as isChatActive, stopChat } from './chatbot';
import { launchSnake } from './snake';
import type { Terminal } from '@xterm/xterm';

/* ── Data initialization ─────────────────────────────── */
const data = portfolioData as PortfolioData;

// Initialize the virtual filesystem from JSON (synchronous at import time)
initFilesystem(data);

/** Current theme key (for neofetch display) */
let currentTheme = 'amber';

/**
 * Extended writer interface that also exposes the raw terminal.
 * Terminal.tsx creates this and passes it to execute().
 */
export interface TerminalWriter extends ITerminalWriter {
  /** Access the raw xterm Terminal for theme changes etc. */
  terminal: Terminal;
}

/* ── Help text ───────────────────────────────────────── */
const HELP_TEXT = [
  '',
  '\x1b[1;38;2;255;176;0m  Available Commands:\x1b[0m',
  '',
  '  \x1b[1;38;2;255;208;96mhelp\x1b[0m          Show this help message',
  '  \x1b[1;38;2;255;208;96mabout\x1b[0m         Who I am',
  '  \x1b[1;38;2;255;208;96mskills\x1b[0m        Technical skills',
  '  \x1b[1;38;2;255;208;96mprojects\x1b[0m      View my projects',
  '  \x1b[1;38;2;255;208;96mcontact\x1b[0m       Get in touch',
  '  \x1b[1;38;2;255;208;96mneofetch\x1b[0m      System info display',
  '  \x1b[1;38;2;255;208;96mls\x1b[0m            List directory contents',
  '  \x1b[1;38;2;255;208;96mcd <dir>\x1b[0m      Change directory',
  '  \x1b[1;38;2;255;208;96mcat <file>\x1b[0m    Display file contents',
  '  \x1b[1;38;2;255;208;96mezra\x1b[0m          Talk to Ezra AI assistant',
  '  \x1b[1;38;2;255;208;96msnake\x1b[0m         Play the snake game',
  '  \x1b[1;38;2;255;208;96mtheme <name>\x1b[0m  Change color theme (' + getAllThemeKeys().join(', ') + ')',
  '  \x1b[1;38;2;255;208;96mclear\x1b[0m         Clear the terminal',
  '  \x1b[1;38;2;255;208;96mreset\x1b[0m         Reset terminal to defaults',
  '',
];

/**
 * Execute a command string and write output via the writer.
 *
 * @param input - Raw input string from the terminal
 * @param w     - TerminalWriter for output
 */
export async function execute(input: string, w: TerminalWriter): Promise<void> {
  const trimmed = input.trim();
  if (!trimmed) return;

  // If the chatbot is active, route input there
  if (isChatActive()) {
    await handleInput(trimmed, w);
    return;
  }

  const parts = trimmed.split(/\s+/);
  const cmd = parts[0].toLowerCase();
  const args = parts.slice(1);

  switch (cmd) {
    /* ── help ─────────────────────────────────────────── */
    case 'help':
      HELP_TEXT.forEach(line => w.writeln(line));
      break;

    /* ── about ────────────────────────────────────────── */
    case 'about': {
      w.writeln('');
      w.writeln(`\x1b[1;38;2;255;140;0m  ${data.owner.name}\x1b[0m`);
      w.writeln(`  ${data.owner.title}`);
      w.writeln(`  ${data.owner.tagline}`);
      w.writeln(`  📍 ${data.owner.location}`);
      w.writeln('');
      data.about.forEach(line => w.writeln(`  ${line}`));
      w.writeln('');
      break;
    }

    /* ── skills ───────────────────────────────────────── */
    case 'skills': {
      w.writeln('');
      for (const [category, items] of Object.entries(data.skills)) {
        w.writeln(`  \x1b[1;38;2;255;176;0m${category}\x1b[0m`);
        w.writeln(`    ${(items as readonly string[]).join('  •  ')}`);
        w.writeln('');
      }
      break;
    }

    /* ── projects ─────────────────────────────────────── */
    case 'projects': {
      w.writeln('');
      for (const p of data.projects) {
        w.writeln(`  \x1b[1;38;2;255;140;0m${p.name}\x1b[0m \x1b[38;2;136;136;136m(${p.year})\x1b[0m`);
        w.writeln(`    ${p.desc}`);
        w.writeln(`    Tech: \x1b[38;2;255;208;96m${p.tech.join(', ')}\x1b[0m`);
        w.writeln('');
      }
      w.writeln(`  \x1b[38;2;136;136;136mType \x1b[1;38;2;255;208;96mcd projects && ls\x1b[0;38;2;136;136;136m for individual files.\x1b[0m`);
      w.writeln('');
      break;
    }

    /* ── contact ──────────────────────────────────────── */
    case 'contact': {
      w.writeln('');
      w.writeln(`  \x1b[1;38;2;255;176;0mContact\x1b[0m`);
      w.writeln(`    📧  ${data.contact.email}`);
      w.writeln(`    🐙  ${data.contact.github}`);
      w.writeln(`    💼  ${data.contact.linkedin}`);
      w.writeln('');
      break;
    }

    /* ── neofetch ─────────────────────────────────────── */
    case 'neofetch':
      renderNeofetch(w, data, currentTheme);
      break;

    /* ── ls ────────────────────────────────────────────── */
    case 'ls':
      ls(args, w);
      break;

    /* ── cd ────────────────────────────────────────────── */
    case 'cd':
      cd(args, w);
      break;

    /* ── cat ───────────────────────────────────────────── */
    case 'cat':
      cat(args, w);
      break;

    /* ── ezra (AI chatbot) ────────────────────────────── */
    case 'ezra':
      await startChat(w);
      break;

    /* ── snake ─────────────────────────────────────────── */
    case 'snake': {
      const container = document.getElementById('crt-wrap');
      if (container) {
        w.writeln('\x1b[38;2;255;176;0m🐍 Snake! Arrow keys to move, Q to quit.\x1b[0m');
        launchSnake(container, () => {
          w.writeln('\x1b[38;2;136;136;136mSnake game closed.\x1b[0m');
        });
      } else {
        w.writeln('\x1b[31mCould not find game container.\x1b[0m');
      }
      break;
    }

    /* ── clear ─────────────────────────────────────────── */
    case 'clear':
      w.clear();
      break;

    /* ── reset ─────────────────────────────────────────── */
    case 'reset':
      w.clear();
      stopChat();
      currentTheme = 'amber';
      w.terminal.options.theme = themes.amber;
      w.writeln('\x1b[38;2;0;230;118mTerminal reset.\x1b[0m');
      w.writeln('');
      break;

    /* ── theme ─────────────────────────────────────────── */
    case 'theme': {
      const name = args[0]?.toLowerCase();
      if (!name || !themes[name]) {
        w.writeln(`Available themes: ${getAllThemeKeys().join(', ')}`);
        break;
      }
      w.terminal.options.theme = themes[name];
      currentTheme = name;
      w.writeln(`\x1b[38;2;0;230;118mTheme changed to '${name}'.\x1b[0m`);
      w.writeln('');
      break;
    }

    /* ── unknown command ──────────────────────────────── */
    default:
      w.writeln(`\x1b[38;2;255;68;68mCommand not found: ${cmd}\x1b[0m`);
      w.writeln(`Type \x1b[1;38;2;255;208;96mhelp\x1b[0m to see available commands.`);
      w.writeln('');
      break;
  }
}

/**
 * Get the current working directory display path.
 * Delegates to the filesystem module.
 */
export function getCwd(): string {
  return fsCwd();
}

/**
 * Get all command names for tab completion.
 * Includes both builtin commands and virtual FS entries.
 */
export function getCompletions(partial: string): string[] {
  const allCommands = [...CONFIG.commands];
  return allCommands.filter(c => c.startsWith(partial.toLowerCase()));
}

/**
 * ─────────────────────────────────────────────────────
 *  Terminal.tsx — Main React island wrapping xterm.js
 *
 *  Initializes an xterm.Terminal inside a DOM ref, loads
 *  FitAddon and WebLinksAddon, manages input buffering,
 *  command history, tab completion, and dispatches to
 *  the command interpreter.
 *
 *  Usage in Astro:
 *    <Terminal client:load onBoot={() => { ... }} />
 * ─────────────────────────────────────────────────────
 */

import { useEffect, useRef } from 'react';
import { Terminal as XTerm } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import '@xterm/xterm/css/xterm.css';

import { CONFIG } from '../terminal/config';
import { amberTheme } from '../terminal/themes';
import { execute, getCompletions, getCwd } from '../terminal/commands';
import type { TerminalWriter } from '../terminal/commands';
import { getSeasonalGreeting } from '../terminal/easter';

/* ── ASCII art banner (hardcoded, no figlet library) ── */
const BANNER = [
  '     ██╗ ██████╗ ███████╗██╗     ',
  '     ██║██╔═══██╗██╔════╝██║     ',
  '     ██║██║   ██║█████╗  ██║     ',
  '██   ██║██║   ██║██╔══╝  ██║     ',
  '╚█████╔╝╚██████╔╝███████╗███████╗',
  ' ╚════╝  ╚═════╝ ╚══════╝╚══════╝',
];

/** Maximum command history entries */
const MAX_HISTORY = 80;

/* ── Props ───────────────────────────────────────────── */

/** @interface TerminalProps */
export interface TerminalProps {
  /**
   * Called once the terminal is mounted and ready.
   * The page can use this to know the terminal is interactive.
   */
  onBoot?: () => void;

  /** Additional CSS class name for the mount container */
  className?: string;
}

/* ── Helpers ─────────────────────────────────────────── */

/**
 * Build the prompt string with ANSI colors.
 * Format: joel01010@portfolio:~$
 */
function buildPrompt(): string {
  const cwdPath = getCwd();
  return `\x1b[1;38;2;255;140;0m${CONFIG.handle.toLowerCase()}@${CONFIG.host}\x1b[0m:\x1b[38;2;255;208;96m${cwdPath}\x1b[0m$ `;
}

/**
 * Get a time-of-day greeting for the welcome message.
 */
function getTimeGreeting(): string {
  const hour = new Date().getHours();

  if (hour >= 5 && hour < 12) {
    return '☀️  Good morning! Ready to explore?';
  } else if (hour >= 12 && hour < 17) {
    return '🌤️  Good afternoon! Welcome aboard.';
  } else if (hour >= 17 && hour < 21) {
    return '🌅  Good evening! Nice to see you.';
  } else {
    return '🌙  Burning the midnight oil? Respect.';
  }
}

/* ── Component ───────────────────────────────────────── */

/**
 * Terminal — Full xterm.js terminal island.
 *
 * Handles:
 * - xterm initialization with amber CRT theme
 * - FitAddon for responsive resizing
 * - WebLinksAddon for clickable URLs
 * - Keystroke buffering, Enter, Backspace, arrows
 * - Command history (up/down, max 80 entries)
 * - Tab completion from command list
 * - FIGlet banner, welcome message, seasonal greeting
 * - Command dispatch to commands.ts interpreter
 */
export default function Terminal({ onBoot, className }: TerminalProps) {
  /** Ref for the DOM element where xterm mounts */
  const mountRef = useRef<HTMLDivElement>(null);

  /** Ref to persist the xterm instance across renders */
  const termRef = useRef<XTerm | null>(null);

  /**
   * Initialize xterm.js in useEffect (requires DOM).
   * Clean up on unmount.
   */
  useEffect(() => {
    const container = mountRef.current;
    if (!container) return;

    /* ── Create terminal instance ───────────────────── */
    const term = new XTerm({
      theme: amberTheme,
      fontFamily: "'Share Tech Mono', 'JetBrains Mono', 'Courier New', monospace",
      fontSize: 14,
      lineHeight: 1.3,
      cursorBlink: true,
      cursorStyle: 'block',
      allowTransparency: true,
      scrollback: 1000,
      convertEol: true,
    });

    termRef.current = term;

    /* ── Load addons ────────────────────────────────── */
    const fitAddon = new FitAddon();
    term.loadAddon(fitAddon);
    term.loadAddon(new WebLinksAddon());

    /* ── Mount to DOM ───────────────────────────────── */
    term.open(container);

    // Initial fit (slight delay to ensure container has dimensions)
    requestAnimationFrame(() => {
      fitAddon.fit();
    });

    /* ── Resize handler ─────────────────────────────── */
    const handleResize = () => {
      fitAddon.fit();
    };
    window.addEventListener('resize', handleResize);

    /* ── Input state ────────────────────────────────── */
    let inputBuffer = '';
    const history: string[] = [];
    let historyIndex = -1;
    let savedInput = ''; // save current input when browsing history
    let executing = false; // prevent input during async command execution

    /* ── Terminal writer for commands ────────────────── */
    const writer: TerminalWriter = {
      writeln: (text: string) => term.writeln(text),
      write: (text: string) => term.write(text),
      clear: () => {
        term.clear();
        term.write('\x1b[H'); // move cursor to top-left
      },
      terminal: term,
    };

    /* ── Print banner & welcome ─────────────────────── */
    term.writeln('');
    BANNER.forEach((line) => {
      term.writeln(`\x1b[38;2;255;102;0m${line}\x1b[0m`);
    });
    term.writeln('');
    term.writeln(`\x1b[1;38;2;255;176;0mWelcome to ${CONFIG.owner}'s CLI Portfolio\x1b[0m`);
    term.writeln(`\x1b[38;2;136;136;136mType \x1b[1;38;2;255;208;96mhelp\x1b[0;38;2;136;136;136m to see available commands.\x1b[0m`);

    // Seasonal greeting (e.g. Halloween, Christmas)
    const seasonal = getSeasonalGreeting();
    if (seasonal) {
      term.writeln(`\x1b[38;2;0;230;118m${seasonal}\x1b[0m`);
    }

    // Time-of-day greeting
    term.writeln(`\x1b[38;2;0;230;118m${getTimeGreeting()}\x1b[0m`);
    term.writeln('');

    // Write initial prompt
    term.write(buildPrompt());

    /* ── Clear the current line and rewrite ──────────── */
    function clearLine() {
      term.write('\r\x1b[K');
      term.write(buildPrompt());
    }

    /* ── Key handler ────────────────────────────────── */
    term.onData((data: string) => {
      // Block input while an async command is running
      if (executing) return;

      const code = data.charCodeAt(0);

      // ── Enter (CR or LF) ─────────────────────────
      if (data === '\r' || data === '\n') {
        term.writeln('');

        const trimmed = inputBuffer.trim();
        if (trimmed) {
          // Add to history (deduplicate consecutive)
          if (history.length === 0 || history[history.length - 1] !== trimmed) {
            history.push(trimmed);
            if (history.length > MAX_HISTORY) history.shift();
          }

          // Execute command (may be async)
          executing = true;
          const savedBuffer = inputBuffer;
          inputBuffer = '';
          historyIndex = -1;
          savedInput = '';

          Promise.resolve(execute(savedBuffer, writer)).then(() => {
            executing = false;
            term.write(buildPrompt());
          }).catch(() => {
            executing = false;
            term.write(buildPrompt());
          });
        } else {
          // Empty input, just print new prompt
          inputBuffer = '';
          historyIndex = -1;
          savedInput = '';
          term.write(buildPrompt());
        }
        return;
      }

      // ── Backspace (127 or \b) ─────────────────────
      if (code === 127 || data === '\b') {
        if (inputBuffer.length > 0) {
          inputBuffer = inputBuffer.slice(0, -1);
          term.write('\b \b');
        }
        return;
      }

      // ── Tab (completion) ──────────────────────────
      if (data === '\t') {
        const parts = inputBuffer.split(/\s+/);
        const partial = parts[parts.length - 1];

        if (partial) {
          const completions = getCompletions(partial);
          if (completions.length === 1) {
            const suffix = completions[0].slice(partial.length);
            inputBuffer += suffix + ' ';
            term.write(suffix + ' ');
          } else if (completions.length > 1) {
            term.writeln('');
            term.writeln(completions.join('  '));
            term.write(buildPrompt() + inputBuffer);
          }
        }
        return;
      }

      // ── Arrow keys (escape sequences) ─────────────
      if (data.startsWith('\x1b[')) {
        const arrow = data.slice(2);

        // Up arrow — previous history
        if (arrow === 'A') {
          if (history.length === 0) return;
          if (historyIndex === -1) {
            savedInput = inputBuffer;
            historyIndex = history.length;
          }
          if (historyIndex > 0) {
            historyIndex--;
            inputBuffer = history[historyIndex];
            clearLine();
            term.write(inputBuffer);
          }
          return;
        }

        // Down arrow — next history
        if (arrow === 'B') {
          if (historyIndex === -1) return;
          historyIndex++;
          if (historyIndex >= history.length) {
            historyIndex = -1;
            inputBuffer = savedInput;
            savedInput = '';
          } else {
            inputBuffer = history[historyIndex];
          }
          clearLine();
          term.write(inputBuffer);
          return;
        }

        // Left/Right arrows — ignore for now
        return;
      }

      // ── Ctrl+C ────────────────────────────────────
      if (code === 3) {
        term.writeln('^C');
        inputBuffer = '';
        historyIndex = -1;
        term.write(buildPrompt());
        return;
      }

      // ── Ctrl+L (clear screen) ────────────────────
      if (code === 12) {
        writer.clear();
        term.write(buildPrompt() + inputBuffer);
        return;
      }

      // ── Regular printable characters ──────────────
      if (code >= 32) {
        inputBuffer += data;
        term.write(data);
      }
    });

    /* ── Focus terminal on click ────────────────────── */
    container.addEventListener('click', () => {
      term.focus();
    });

    /* ── Signal boot complete ───────────────────────── */
    if (onBoot) {
      onBoot();
    }

    /* ── Cleanup on unmount ─────────────────────────── */
    return () => {
      window.removeEventListener('resize', handleResize);
      term.dispose();
      termRef.current = null;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div
      ref={mountRef}
      id="terminal-mount"
      className={className || ''}
      role="application"
      aria-label="Interactive CLI terminal"
    />
  );
}

